    assert exists c | 0 <= c < |grid[top]| :: grid[top][c] == '*';
    var j := 0;
    var jDone := false;
    while j < m && !jDone
      invariant 0 <= j <= m
      invariant !jDone ==> forall c | 0 <= c < j :: grid[top][c] != '*'
      invariant jDone ==> 0 <= j < m && grid[top][j] == '*'
      decreases m - j, !jDone
    {
      if grid[top][j] == '*' {
        jDone := true;
      } else {
        j := j + 1;
      }
    }
    if jDone {
      topDone := true;
    } else {
      assert forall c | 0 <= c < |grid[top]| :: grid[top][c] != '*';
      top := top + 1;
    }
  }
