    } else {
      assert exists c | 0 <= c < |grid[bot]| :: grid[bot][c] == '*';
      bot := bot - 1;
    }
  }
  if !botDone {
    assert forall r | 0 <= r < n :: forall c | 0 <= c < |grid[r]| :: grid[r][c] != '*';
    assert false;
